const output = $input.first().json.output;

let emailData = {
  email_to: '',
  email_subject: 'Appointment Confirmation - Dr. Strange',
  email_body: output
};

try {
  // Try to extract JSON_EMAIL_DATA format
  const jsonMatch = output.match(/JSON_EMAIL_DATA:\s*(\{[^}]+\})/s);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[1]);
    if (parsed.email_to && parsed.email_to.includes('@')) {
      emailData = parsed;
    }
  } else {
    // Try to find any JSON object with email_to field
    const anyJsonMatch = output.match(/\{[^}]*"email_to"[^}]*\}/s);
    if (anyJsonMatch) {
      const parsed = JSON.parse(anyJsonMatch[0]);
      if (parsed.email_to && parsed.email_to.includes('@')) {
        emailData = parsed;
      }
    }
  }
} catch (error) {
  // If parsing fails, try to extract email from the text
  const emailMatch = output.match(/\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/);
  if (emailMatch) {
    emailData.email_to = emailMatch[0];
  }
}

// If still no email, throw error with helpful message
if (!emailData.email_to || !emailData.email_to.includes('@')) {
  throw new Error('Could not extract valid email address from AI output. AI must provide email in JSON format.');
}

return [{ json: emailData }];
